// ═══ HELPERS ═══

export function getMainProducts(): HubSpotProduct[] {
  return HUBSPOT_PRODUCTS.filter(p => !p.isMontaje);
}

export function getMontajeProducts(): HubSpotProduct[] {
  return HUBSPOT_PRODUCTS.filter(p => p.isMontaje);
}

export function searchHubSpotProducts(query: string): HubSpotProduct[] {
  const q = query.toLowerCase();
  return HUBSPOT_PRODUCTS.filter(p => p.name.toLowerCase().includes(q) || p.description.toLowerCase().includes(q));
}

export function getProductWithMontaje(productId: string): { product: HubSpotProduct | undefined; montaje: HubSpotProduct | undefined } {
  const product = HUBSPOT_PRODUCTS.find(p => p.id === productId);
  if (!product) return { product: undefined, montaje: undefined };
  const baseName = product.name.replace(/ \|.*$/, "").trim();
  const montaje = HUBSPOT_PRODUCTS.find(p => p.isMontaje && p.name.includes(baseName));
  return { product, montaje };
}